#!/usr/bin/env node
/**
 * generate:openapi — embeds the repo's canonical OpenAPI document
 * (docs/api/openapi.yaml, the single source of truth) as a build-time
 * string asset so the public spec route (/docs/api/openapi.yaml) ships
 * inside the web bundle with no runtime filesystem dependency (works in
 * standalone/container output where docs/ does not ship).
 *
 * Output (src/generated/openapi.ts) is gitignored and regenerated by the
 * `pre*` hooks on every dev/build/typecheck run — never edit or commit it.
 * Org web standard: this file is byte-identical across apparule, expendit
 * and upstat.
 */

import { mkdirSync, readFileSync, writeFileSync } from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

const webRoot = join(dirname(fileURLToPath(import.meta.url)), "..");
const specPath = join(webRoot, "..", "docs", "api", "openapi.yaml");
const outDir = join(webRoot, "src", "generated");
const outPath = join(outDir, "openapi.ts");

const spec = readFileSync(specPath, "utf8");

const banner = [
  "// AUTO-GENERATED by scripts/generate-openapi-asset.mjs — do not edit.",
  "// Source of truth: docs/api/openapi.yaml (repo root). Gitignored;",
  "// regenerated on every dev/build/typecheck run.",
].join("\n");

mkdirSync(outDir, { recursive: true });
writeFileSync(
  outPath,
  `${banner}\nexport const openApiYaml: string = ${JSON.stringify(spec)};\n`,
);

console.log(`generate:openapi — embedded ${specPath} → ${outPath}`);
